#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)b - *(int*)a);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *visitOrder = (int*)malloc(m * sizeof(int));
        for (int i = 0; i < m; i++) {
            scanf("%d", &visitOrder[i]);
        }
        int **rooms = (int**)malloc(n * sizeof(int*));
        int *bottleCounts = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &bottleCounts[i]);
            rooms[i] = (int*)malloc(bottleCounts[i] * sizeof(int));
            for (int j = 0; j < bottleCounts[i]; j++) {
                scanf("%d", &rooms[i][j]);
            }
            qsort(rooms[i], bottleCounts[i], sizeof(int), compare);
        }
        int totalLemonade = 0;
        for (int i = 0; i < m; i++) {
            int roomIndex = visitOrder[i];
            if (bottleCounts[roomIndex] > 0) {
                totalLemonade += rooms[roomIndex][0];
                for (int k = 1; k < bottleCounts[roomIndex]; k++) {
                    rooms[roomIndex][k - 1] = rooms[roomIndex][k];
                }
                bottleCounts[roomIndex]--;
            }
        }
        printf("%d\n", totalLemonade);
        for (int i = 0; i < n; i++) {
            free(rooms[i]);
        }
        free(rooms);
        free(visitOrder);
        free(bottleCounts);
    }
    return 0;
}

