class Main
{
    public static void main(String[] args) throws java.lang.Exception
    {
        Scanner scanner = new Scanner(System.in);
        int testCases = scanner.nextInt();
        while (testCases-- > 0) {
            int numRooms = scanner.nextInt();
            int numVisits = scanner.nextInt();
            int[] roomVisits = new int[numVisits];
            for (int i = 0; i < numVisits; i++) {
                roomVisits[i] = scanner.nextInt();
            }
            int[][] bottlesInRooms = new int[numRooms][];
            for (int i = 0; i < numRooms; i++) {
                int numBottles = scanner.nextInt();
                bottlesInRooms[i] = new int[numBottles];
                for (int j = 0; j < numBottles; j++) {
                    bottlesInRooms[i][j] = scanner.nextInt();
                }
                Arrays.sort(bottlesInRooms[i]);
                reverse(bottlesInRooms[i]);
            }
            int totalLemonadeVolume = 0;
            for (int i = 0; i < numVisits; i++) {
                int visitedRoom = roomVisits[i];
                if (bottlesInRooms[visitedRoom].length > 0) {
                    int maxLemonadeVolume = bottlesInRooms[visitedRoom][0];
                    totalLemonadeVolume += maxLemonadeVolume;
                    bottlesInRooms[visitedRoom] = Arrays.copyOfRange(bottlesInRooms[visitedRoom], 1, bottlesInRooms[visitedRoom].length);
                }
            }
            System.out.println(totalLemonadeVolume);
        }
        scanner.close();
    }
    public static void reverse(int[] array) {
        int left = 0;
        int right = array.length - 1;
        while (left < right) {
            int temp = array[left];
            array[left] = array[right];
            array[right] = temp;
            left++;
            right--;
        }
    }
}

