# Function to solve the problem
def solve(visit_order, rooms):
    total_drunk = 0
    for room_index in visit_order:
        if not rooms[room_index]:
            continue
        else:
            max_volume = max(rooms[room_index])
            total_drunk += max_volume
            rooms[room_index].remove(max_volume)
    return total_drunk

# Main execution to read input and call the solve function
def main():
    test_cases = int(input())
    for _ in range(test_cases):
        n, m = map(int, input().split())
        visit_order = list(map(int, input().split()))
        rooms = []
        for _ in range(n):
            room_data = list(map(int, input().split()))[1:]
            room_data.sort(reverse=True)
            rooms.append(room_data)
        print(solve(visit_order, rooms))

# Entry point of the program
if __name__ == "__main__":
    main()

